 21→
 22→const { h } = window;
 23→
 24→const querySearchInput = async () => {
 25→  const input =
 26→    h.app.excalidrawContainerValue.container?.querySelector<HTMLInputElement>(
 27→      `.${CLASSES.SEARCH_MENU_INPUT_WRAPPER} input`,
 28→    )!;
