 32→
 33→describe("search", () => {
 34→  beforeEach(async () => {
 35→    await render(<Excalidraw handleKeyboardGlobally />);
 36→    API.setAppState({
 37→      openSidebar: null,
 38→    });
 39→  });
 40→
 41→  it("should toggle search on cmd+f", async () => {
 42→    expect(h.app.state.openSidebar).toBeNull();
 43→
 44→    Keyboard.withModifierKeys({ ctrl: true }, () => {
 45→      Keyboard.keyPress(KEYS.F);
 46→    });
 47→    expect(h.app.state.openSidebar).not.toBeNull();
 48→    expect(h.app.state.openSidebar?.name).toBe(DEFAULT_SIDEBAR.name);
 49→    expect(h.app.state.openSidebar?.tab).toBe(CANVAS_SEARCH_TAB);
 50→
 51→    const searchInput = await querySearchInput();
 52→    expect(searchInput.matches(":focus")).toBe(true);
 53→  });
 54→
 55→  it("should refocus search input with cmd+f when search sidebar is still open", async () => {
 56→    Keyboard.withModifierKeys({ ctrl: true }, () => {
 57→      Keyboard.keyPress(KEYS.F);
 58→    });
 59→
 60→    const searchInput =
 61→      h.app.excalidrawContainerValue.container?.querySelector<HTMLInputElement>(
 62→        `.${CLASSES.SEARCH_MENU_INPUT_WRAPPER} input`,
 63→      );
 64→
 65→    act(() => {
 66→      searchInput?.blur();
 67→    });
 68→
 69→    expect(h.app.state.openSidebar).not.toBeNull();
 70→    expect(searchInput?.matches(":focus")).toBe(false);
 71→
 72→    Keyboard.withModifierKeys({ ctrl: true }, () => {
 73→      Keyboard.keyPress(KEYS.F);
 74→    });
 75→    expect(searchInput?.matches(":focus")).toBe(true);
 76→  });
 77→
 78→  it("should match text and cycle through matches on Enter", async () => {
 79→    const scrollIntoViewMock = jest.fn();
 80→    window.HTMLElement.prototype.scrollIntoView = scrollIntoViewMock;
 81→
 82→    API.setElements([
 83→      API.createElement({ type: "text", text: "test one" }),
