158→      expect(h.app.state.searchMatches?.matches[0]?.matchedLines?.length).toBe(
159→        6,
160→      );
161→    });
162→  });
163→
164→  it("should match frame names", async () => {
165→    const scrollIntoViewMock = jest.fn();
166→    window.HTMLElement.prototype.scrollIntoView = scrollIntoViewMock;
