   551→const getMatchPreview = (
   552→  text: string,
   553→  index: number,
   554→  searchQuery: SearchQuery,
   555→) => {
   556→  const WORDS_BEFORE = 2;
   557→  const WORDS_AFTER = 5;
   558→
   559→  const substrBeforeQuery = text.slice(0, index);
   560→  const wordsBeforeQuery = substrBeforeQuery.split(/\s+/);
   561→  // text = "small", query = "mall", not complete before
   562→  // text = "small", query = "smal", complete before
   563→  const isQueryCompleteBefore = substrBeforeQuery.endsWith(" ");
   564→  const startWordIndex =
   565→    wordsBeforeQuery.length -
   566→    WORDS_BEFORE -
   567→    1 -
   568→    (isQueryCompleteBefore ? 0 : 1);
   569→  let wordsBeforeAsString =
   570→    wordsBeforeQuery.slice(startWordIndex <= 0 ? 0 : startWordIndex).join(" ") +
   571→    (isQueryCompleteBefore ? " " : "");
   572→
   573→  const MAX_ALLOWED_CHARS = 20;
   574→
   575→  wordsBeforeAsString =
   576→    wordsBeforeAsString.length > MAX_ALLOWED_CHARS
   577→      ? wordsBeforeAsString.slice(-MAX_ALLOWED_CHARS)
