   704→      if (textElement.textAlign !== "left" && lineIndexRange.line.length > 0) {
   705→        const lineLength = measureText(
   706→          lineIndexRange.line,
   707→          getFontString(textElement),
   708→          textElement.lineHeight,
   709→        );
   710→
   711→        const spaceToStart =
   712→          textElement.textAlign === "center"
   713→            ? (textElement.width - lineLength.width) / 2
   714→            : textElement.width - lineLength.width;
   715→        offset.width += spaceToStart;
   716→      }
   717→
   718→      const { width, height } = measureText(
   719→        matchedWord,
   720→        getFontString(textElement),
   721→        textElement.lineHeight,
   722→      );
