   773→    {
   774→      offsetX,
   775→      offsetY,
   776→      width,
   777→      height: matchedMetrics.height,
   778→      showOnCanvas: offsetX + width <= frame.width * zoomValue,
   779→    },
   780→  ];
   781→};
